
"use client"

import { useState, useEffect, useMemo } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { 
  Zap, Loader2, Navigation, ShieldAlert, Timer, Flag, Trophy, Activity, MapPin, Star, Clock, ArrowUpRight, Play, Target
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking, useCollection } from "@/firebase";
import { doc, collection, query, where, getCountFromServer, orderBy, limit } from "firebase/firestore";
import { useDriving, RunMode } from "@/context/driving-context";
import { RenderCarIcon } from "@/components/icons/car-icons";

const RouteMap = dynamic(() => import("../../components/telemetry/route-map"), { 
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center bg-zinc-900/50 rounded-3xl">
      <Loader2 className="w-6 h-6 animate-spin text-red-500" />
    </div>
  )
});

type ReportType = 'Radar' | 'Polici' | 'Kontrollë';

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const { 
    speed, isDriving, peakSpeed, tripTime, tripDistance, hasGps, 
    currentCoords, heading, routePoints, telemetry, startTime,
    runMode, dragTime, isDragFinished, isWakeLockActive,
    setRunMode, startTrip, stopTrip, resetTrip, requestWakeLock 
  } = useDriving();
  
  const [mounted, setMounted] = useState(false);
  const [isReporting, setIsReporting] = useState<ReportType | null>(null);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [cityRank, setCityRank] = useState<number | null>(null);
  const [kosovoRank, setKosovoRank] = useState<number | null>(null);
  const [isRankingLoading, setIsRankingLoading] = useState(false);
  
  const { toast } = useToast();

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  const calculateRanks = async () => {
    if (!db || !profile) return;
    setIsRankingLoading(true);
    
    try {
      const publicRunsCol = collection(db, "public_runs");
      let kosovoQuery;
      let cityQuery;

      if (runMode === 'free') {
        const val = peakSpeed;
        if (val <= 0) {
          setIsRankingLoading(false);
          return;
        }
        kosovoQuery = query(publicRunsCol, where("runType", "==", "Top Speed"), where("peakSpeedKmH", ">", val));
        if (profile.city) {
          cityQuery = query(publicRunsCol, where("city", "==", profile.city), where("runType", "==", "Top Speed"), where("peakSpeedKmH", ">", val));
        }
      } else {
        const modeName = runMode === '0-100' ? '0-100' : runMode === '100-200' ? '100-200' : '1/4 Mile';
        const val = dragTime;
        if (!val) {
          setIsRankingLoading(false);
          return;
        }
        kosovoQuery = query(publicRunsCol, where("runType", "==", modeName), where("dragTime", "<", val));
        if (profile.city) {
          cityQuery = query(publicRunsCol, where("city", "==", profile.city), where("runType", "==", modeName), where("dragTime", "<", val));
        }
      }

      const kosovoSnapshot = await getCountFromServer(kosovoQuery);
      setKosovoRank(kosovoSnapshot.data().count + 1);

      if (cityQuery) {
        const citySnapshot = await getCountFromServer(cityQuery);
        setCityRank(citySnapshot.data().count + 1);
      }
    } catch (e) {
      console.error("Ranking calculation failed:", e);
    } finally {
      setIsRankingLoading(false);
    }
  };

  useEffect(() => {
    if (isDragFinished && mounted && !showSummary) {
      setShowSummary(true);
      calculateRanks();
      toast({ title: "GARA U KRYE", description: `Koha: ${dragTime?.toFixed(2)}s` });
    }
  }, [isDragFinished, dragTime, mounted, showSummary]);

  const handleStartMission = () => {
    startTrip();
    requestWakeLock();
  };

  const handleStopMission = () => {
    stopTrip();
    setShowSummary(true);
    calculateRanks();
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const rpm = useMemo(() => {
    if (speed === 0) return 800;
    const gear = Math.floor(speed / 60) + 1;
    const speedInGear = speed % 60;
    const baseRpm = 1200 + (gear * 100);
    const calculated = baseRpm + (speedInGear * 110);
    return Math.min(Math.floor(calculated), 8000);
  }, [speed]);

  const handleQuickReport = async (type: ReportType) => {
    if (!db || !currentCoords || !user?.uid) {
      toast({ variant: "destructive", title: "GABIM", description: "Lejoni GPS-in për të raportuar." });
      return;
    }
    setIsReporting(type);
    
    let locationName = profile?.city || "Kosovë";
    try {
      const response = await fetch(`https://photon.komoot.io/reverse?lon=${currentCoords.lng}&lat=${currentCoords.lat}`);
      const data = await response.json();
      if (data.features && data.features.length > 0) {
        const p = data.features[0].properties;
        locationName = p.name || p.street || p.city || locationName;
      }
    } catch (e) { console.warn("Geocoding failed"); }

    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type,
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: locationName,
      city: profile?.city || "Kosovë",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });
    
    setTimeout(() => {
      setIsReporting(null);
      toast({ title: "RAPORTUAR", description: `${type} u shënua në hartë.` });
    }, 400);
  };

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Prishtinë",
      runType: runMode === 'free' ? 'Top Speed' : runMode === '0-100' ? '0-100' : runMode === '100-200' ? '100-200' : '1/4 Mile',
      startTime: startTime?.toISOString() || new Date().toISOString(),
      endTime: new Date().toISOString(),
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      dragTime: dragTime,
      telemetry: telemetry,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };
    
    const userRunsCol = collection(db, "users", user.uid, "runs");
    addDocumentNonBlocking(userRunsCol, runData);
    
    const publicRunsCol = collection(db, "public_runs");
    addDocumentNonBlocking(publicRunsCol, runData);
    
    toast({ title: "U RUAJT", description: "Të dhënat u sinkronizuan në Ranking." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
    setCityRank(null);
    setKosovoRank(null);
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  return (
    <div className="flex flex-col min-h-full bg-black text-foreground pb-24 overflow-x-hidden safe-top relative no-scrollbar">
      {/* Background Glow */}
      <div className="absolute inset-0 bg-gradient-to-b from-red-600/5 via-transparent to-transparent pointer-events-none" />
      
      {/* Top Status Bar */}
      <div className="p-5 space-y-4 z-20 shrink-0">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-zinc-900/50 border border-white/5 flex items-center justify-center">
                <RenderCarIcon type={profile?.profileIcon} className="w-5 h-5 text-red-500" />
             </div>
             <div>
                <h1 className="text-xs font-black uppercase tracking-tight text-white leading-none">{profile?.username || "SHOFER"}</h1>
                <div className="flex items-center gap-1.5 mt-1">
                  <div className={cn("w-1 h-1 rounded-full", isWakeLockActive ? "bg-red-500 shadow-[0_0_8px_#ef4444]" : "bg-zinc-700")} />
                  <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">
                    {isWakeLockActive ? "HUD AKTIV" : "SISTEMI GATI"}
                  </span>
                </div>
             </div>
          </div>
          <Badge variant="outline" className="text-[7px] font-black uppercase border-white/5 text-muted-foreground bg-white/5 py-1 px-3 tracking-widest rounded-lg">
            {hasGps ? "TELEMETRI LIVE" : "KËRKOHET GPS"}
          </Badge>
        </div>

        {!hasGps && (
          <Alert variant="destructive" className="rounded-2xl bg-red-950/20 border-red-500/20 py-2.5">
            <ShieldAlert className="h-3 w-3 text-red-500" />
            <AlertTitle className="text-[8px] font-black uppercase tracking-widest text-red-500">GPS ERROR</AlertTitle>
          </Alert>
        )}

        {/* Quick Report Bar */}
        <div className="grid grid-cols-3 gap-2.5">
          {[
            { id: 'Radar', label: 'RADAR', emoji: '🚨', color: 'red' },
            { id: 'Polici', label: 'POLICI', emoji: '🚔', color: 'blue' },
            { id: 'Kontrollë', label: 'PONT', emoji: '🚗', color: 'zinc' }
          ].map((item) => (
            <Button 
              key={item.id}
              onClick={() => handleQuickReport(item.id as ReportType)} 
              disabled={!!isReporting} 
              className={cn(
                "h-12 flex flex-col items-center justify-center gap-0.5 rounded-xl border transition-all active:scale-95",
                item.color === 'red' ? "bg-red-600/5 border-red-500/10 text-red-500" :
                item.color === 'blue' ? "bg-blue-600/5 border-blue-500/10 text-blue-400" :
                "bg-white/5 border-white/5 text-zinc-400"
              )}
            >
              <span className="text-sm">{item.emoji}</span>
              <span className="text-[7px] font-black uppercase tracking-widest">{item.label}</span>
            </Button>
          ))}
        </div>
      </div>

      {/* Main Center Section */}
      <div className="flex-1 flex flex-col items-center justify-center relative px-6 py-2">
        {/* Mode Selector - iOS Segmented Control Style */}
        <div className="w-full max-w-[280px] mb-8 z-20">
          <div className="bg-zinc-900/50 backdrop-blur-3xl p-1 rounded-xl border border-white/5 flex gap-1">
            {[
              { id: 'free', label: 'LIRË', icon: Navigation },
              { id: '0-100', label: '0-100', icon: Zap },
              { id: '100-200', label: '100-200', icon: Clock },
              { id: '1/4mile', label: '1/4 M', icon: Flag }
            ].map((mode) => (
              <button 
                key={mode.id}
                onClick={() => !isDriving && setRunMode(mode.id as RunMode)}
                className={cn(
                  "flex-1 h-9 flex flex-col items-center justify-center rounded-lg transition-all",
                  runMode === mode.id 
                    ? "bg-red-600 text-white shadow-lg shadow-red-600/20" 
                    : "text-muted-foreground hover:bg-white/5",
                  isDriving && "opacity-40 cursor-not-allowed"
                )}
              >
                <mode.icon className="w-3 h-3" />
                <span className="text-[6px] font-black uppercase tracking-widest mt-0.5">{mode.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* The Digital Cockpit Gauge - Optimized for Mobile */}
        <div className="relative w-full aspect-square flex items-center justify-center max-w-[280px] mx-auto mb-8">
          <div className="w-full h-full relative flex items-center justify-center">
            {/* RPM Ring */}
            <svg viewBox="0 0 400 400" className="w-full h-full transform -rotate-90 absolute inset-0 overflow-visible">
              <circle cx="200" cy="200" r="185" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-white/[0.05]" />
              <circle
                cx="200" cy="200" r="185"
                stroke="currentColor" strokeWidth="4" strokeLinecap="butt"
                fill="transparent"
                strokeDasharray={2 * Math.PI * 185}
                style={{ 
                  strokeDashoffset: (2 * Math.PI * 185) - (rpm / 8000) * (2 * Math.PI * 185),
                  transition: 'stroke-dashoffset 0.2s cubic-bezier(0.4, 0, 0.2, 1)'
                }}
                className={cn(
                  "transition-all",
                  rpm > 7000 ? "text-red-600 drop-shadow-[0_0_12px_#ef4444]" : "text-red-600/30"
                )}
              />
            </svg>
            
            {/* Speed Center */}
            <div className="z-20 flex flex-col items-center justify-center">
              <span className={cn(
                "font-black tracking-tighter leading-none tabular-nums text-white",
                speed > 99 ? "text-[7rem]" : "text-[8.5rem]"
              )}>
                {speed}
              </span>
              <div className="flex flex-col items-center -mt-4">
                <span className="text-[12px] font-black uppercase tracking-[0.5em] text-red-600 opacity-90">KM/H</span>
              </div>
            </div>
          </div>
        </div>

        {/* Live Telemetry Data - Restored & Optimized */}
        <div className="w-full max-w-[280px] grid grid-cols-2 gap-3 mb-8 z-20">
           <div className="bg-zinc-900/40 border border-white/5 p-3 rounded-2xl flex flex-col items-center backdrop-blur-xl">
             <span className="text-[7px] font-black text-muted-foreground uppercase tracking-widest mb-1">DISTANCA</span>
             <span className="text-xs font-black text-white">{(tripDistance / 1000).toFixed(2)} KM</span>
           </div>
           <div className="bg-zinc-900/40 border border-white/5 p-3 rounded-2xl flex flex-col items-center backdrop-blur-xl">
             <span className="text-[7px] font-black text-muted-foreground uppercase tracking-widest mb-1">MAX SPEED</span>
             <span className="text-xs font-black text-red-500">{peakSpeed} KM/H</span>
           </div>
        </div>

        {/* Main Action Button - Apple Pill Style */}
        <div className="w-full max-w-[280px] z-20">
          <Button 
            onClick={() => isDriving ? handleStopMission() : handleStartMission()} 
            className={cn(
              "w-full h-14 rounded-full font-black text-base uppercase tracking-[0.15em] transition-all shadow-2xl active:scale-95 border-none", 
              isDriving 
                ? "bg-zinc-900 text-white border border-white/10" 
                : "bg-red-600 hover:bg-red-700 text-white shadow-red-600/30"
            )}
          >
            {isDriving ? "STOP TRIP" : "START TRIP"}
          </Button>
        </div>
      </div>

      {/* Race Summary Dialog */}
      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="bg-black border-white/10 w-[92%] max-w-sm rounded-[2rem] p-0 shadow-2xl overflow-hidden">
          <div className="p-7 space-y-6">
            <div className="flex flex-col items-center gap-2">
              <Trophy className="w-8 h-8 text-red-500" />
              <DialogTitle className="text-lg font-black uppercase tracking-tight text-center">REZULTATI I GARËS</DialogTitle>
            </div>
            
            <div className="space-y-4">
              <Card className="bg-zinc-950 border-white/5 p-4 rounded-2xl space-y-4">
                <div className="h-32 w-full rounded-xl border border-white/5 overflow-hidden grayscale">
                  <RouteMap points={routePoints} />
                </div>
                <div className="grid grid-cols-3 gap-2">
                  <div className="bg-white/5 p-2.5 rounded-xl flex flex-col items-center">
                    <Timer className="w-3 h-3 text-muted-foreground mb-1" />
                    <span className="text-[9px] font-black text-white">{formatTime(tripTime)}</span>
                  </div>
                  <div className="bg-white/5 p-2.5 rounded-xl flex flex-col items-center">
                    <MapPin className="w-3 h-3 text-red-500 mb-1" />
                    <span className="text-[9px] font-black text-white">{(tripDistance / 1000).toFixed(2)}</span>
                  </div>
                  <div className="bg-white/5 p-2.5 rounded-xl flex flex-col items-center">
                    <Zap className="w-3 h-3 text-yellow-500 mb-1" />
                    <span className="text-[9px] font-black text-white">{peakSpeed}</span>
                  </div>
                </div>
              </Card>

              <Card className="bg-red-600/5 border-red-500/10 p-4 rounded-2xl">
                 {isRankingLoading ? (
                   <div className="flex items-center justify-center py-2 gap-2">
                     <Loader2 className="w-4 h-4 animate-spin text-red-500" />
                     <span className="text-[7px] font-black uppercase tracking-widest text-muted-foreground">Llogaritja...</span>
                   </div>
                 ) : (
                   <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                         <Star className="w-4 h-4 text-red-500 fill-red-500" />
                         <div className="flex flex-col">
                           <span className="text-[8px] font-black text-red-500 uppercase tracking-widest">KOSOVË</span>
                           <span className="text-xs font-black text-white">#{kosovoRank || '--'} 🔥</span>
                         </div>
                      </div>
                      <div className="text-right">
                         <span className="text-[8px] font-black text-muted-foreground uppercase tracking-widest">{profile?.city || "QYTETI"}</span>
                         <p className="text-xs font-black text-white">#{cityRank || '--'}</p>
                      </div>
                   </div>
                 )}
              </Card>
            </div>

            <div className="flex flex-col gap-2 pt-2">
              <Button onClick={handleSaveRun} disabled={isSaving || isRankingLoading} className="w-full h-12 bg-red-600 text-white rounded-full font-black uppercase text-xs">RUAJ TË DHËNAT</Button>
              <Button variant="ghost" className="w-full h-10 rounded-xl font-black uppercase text-[8px] text-zinc-500" onClick={() => { setShowSummary(false); resetTrip(); setCityRank(null); setKosovoRank(null); }}>FSHIJ REZULTATIN</Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
      <BottomNav />
    </div>
  );
}
